import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../context/AuthContext';
import { patientAPI, prescriptionAPI } from '../services/api';
import { 
  FaUser, 
  FaEdit, 
  FaSave, 
  FaTimes,
  FaCalendarAlt,
  FaPrescription,
  FaFileAlt,
  FaHeart,
  FaPhone,
  FaMapMarkerAlt,
  FaTint,
  FaAllergies,
  FaHistory,
  FaDownload,
  FaEye
} from 'react-icons/fa';

const Profile = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  
  const [profileData, setProfileData] = useState({
    name: '',
    age: '',
    gender: '',
    phone: '',
    address: '',
    emergency_contact: '',
    blood_group: '',
    allergies: '',
    medical_history: ''
  });

  const [prescriptions, setPrescriptions] = useState([]);
  const [medicalHistory, setMedicalHistory] = useState([]);

  // Dummy data for demonstration
  const dummyProfile = {
    name: 'Rajesh Kumar',
    age: 35,
    gender: 'male',
    phone: '+91 98765 43210',
    address: 'Village Nabha, District Patiala, Punjab 147201',
    emergency_contact: '+91 98765 43211',
    blood_group: 'B+',
    allergies: 'Penicillin, Nuts',
    medical_history: 'Hypertension since 2020, Diabetes since 2022'
  };

  const dummyPrescriptions = [
    {
      id: '1',
      doctor_name: 'Dr. Priya Sharma',
      doctor_specialty: 'Pediatrics',
      date: '2024-01-10',
      diagnosis: 'Common Cold',
      medicines: [
        { name: 'Paracetamol 500mg', dosage: '1 tablet twice daily', duration: '3 days' },
        { name: 'Cetirizine 10mg', dosage: '1 tablet at bedtime', duration: '5 days' }
      ],
      instructions: 'Take plenty of rest and fluids. Avoid cold drinks.'
    },
    {
      id: '2',
      doctor_name: 'Dr. Rajesh Kumar',
      doctor_specialty: 'Cardiology',
      date: '2023-12-15',
      diagnosis: 'Hypertension Follow-up',
      medicines: [
        { name: 'Amlodipine 5mg', dosage: '1 tablet daily morning', duration: '30 days' },
        { name: 'Metoprolol 25mg', dosage: '1 tablet twice daily', duration: '30 days' }
      ],
      instructions: 'Regular BP monitoring. Low salt diet. Regular exercise.'
    }
  ];

  const dummyHistory = [
    {
      id: '1',
      date: '2024-01-10',
      type: 'Consultation',
      doctor: 'Dr. Priya Sharma',
      description: 'Video consultation for cold and cough symptoms',
      status: 'Completed'
    },
    {
      id: '2',
      date: '2023-12-15',
      type: 'Follow-up',
      doctor: 'Dr. Rajesh Kumar',
      description: 'Hypertension follow-up and medication review',
      status: 'Completed'
    },
    {
      id: '3',
      date: '2023-11-20',
      type: 'Lab Test',
      doctor: 'Lab Technician',
      description: 'Blood sugar and HbA1c test',
      status: 'Completed'
    }
  ];

  useEffect(() => {
    fetchProfileData();
    fetchPrescriptions();
    fetchMedicalHistory();
  }, []);

  const fetchProfileData = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      setProfileData(dummyProfile);
    } catch (error) {
      console.error('Error fetching profile:', error);
      setProfileData(dummyProfile); // Fallback to dummy data
    } finally {
      setLoading(false);
    }
  };

  const fetchPrescriptions = async () => {
    try {
      setPrescriptions(dummyPrescriptions);
    } catch (error) {
      console.error('Error fetching prescriptions:', error);
      setPrescriptions(dummyPrescriptions);
    }
  };

  const fetchMedicalHistory = async () => {
    try {
      setMedicalHistory(dummyHistory);
    } catch (error) {
      console.error('Error fetching medical history:', error);
      setMedicalHistory(dummyHistory);
    }
  };

  const handleInputChange = (e) => {
    setProfileData({
      ...profileData,
      [e.target.name]: e.target.value
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll just simulate the save
      console.log('Saving profile data:', profileData);
      alert('Profile updated successfully!');
      setIsEditing(false);
    } catch (error) {
      console.error('Error saving profile:', error);
      alert('Failed to update profile. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    fetchProfileData(); // Reset to original data
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN');
  };

  const tabs = [
    { id: 'profile', label: 'Personal Info', icon: FaUser },
    { id: 'prescriptions', label: 'Prescriptions', icon: FaPrescription },
    { id: 'history', label: 'Medical History', icon: FaHistory }
  ];

  if (loading && !profileData.name) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading profile...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          Patient {t('profile')}
        </h1>
        <p className="text-gray-600">
          Manage your personal information and medical records
        </p>
      </div>

      {/* Profile Header */}
      <div className="bg-white rounded-lg shadow-sm border p-6 mb-8">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-20 h-20 bg-gradient-to-br from-primary-color to-primary-dark rounded-full flex items-center justify-center text-white text-2xl font-bold">
              {profileData.name ? profileData.name.charAt(0) : 'U'}
            </div>
            <div>
              <h2 className="text-2xl font-bold text-gray-900">{profileData.name}</h2>
              <p className="text-gray-600">
                {profileData.age} years • {profileData.gender} • {profileData.blood_group}
              </p>
              <p className="text-sm text-gray-500">{user?.email}</p>
            </div>
          </div>

          {!isEditing && (
            <button
              onClick={() => setIsEditing(true)}
              className="btn btn-outline flex items-center gap-2"
            >
              <FaEdit />
              Edit Profile
            </button>
          )}

          {isEditing && (
            <div className="flex gap-2">
              <button
                onClick={handleCancel}
                className="btn btn-outline flex items-center gap-2"
              >
                <FaTimes />
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={loading}
                className="btn btn-primary flex items-center gap-2"
              >
                {loading ? <div className="loading w-4 h-4"></div> : <FaSave />}
                Save
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
        <div className="border-b">
          <div className="flex">
            {tabs.map((tab) => {
              const Icon = tab.icon;
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`flex items-center gap-2 px-6 py-4 border-b-2 transition-colors ${
                    activeTab === tab.id
                      ? 'border-primary-color text-primary-color bg-primary-light'
                      : 'border-transparent text-gray-600 hover:text-gray-900'
                  }`}
                >
                  <Icon />
                  {tab.label}
                </button>
              );
            })}
          </div>
        </div>

        {/* Tab Content */}
        <div className="p-6">
          {/* Profile Tab */}
          {activeTab === 'profile' && (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="form-group">
                  <label className="label">{t('name')}</label>
                  {isEditing ? (
                    <input
                      type="text"
                      name="name"
                      value={profileData.name}
                      onChange={handleInputChange}
                      className="input"
                    />
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaUser className="text-gray-400" />
                      <span>{profileData.name}</span>
                    </div>
                  )}
                </div>

                <div className="form-group">
                  <label className="label">{t('phone')}</label>
                  {isEditing ? (
                    <input
                      type="tel"
                      name="phone"
                      value={profileData.phone}
                      onChange={handleInputChange}
                      className="input"
                    />
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaPhone className="text-gray-400" />
                      <span>{profileData.phone}</span>
                    </div>
                  )}
                </div>

                <div className="form-group">
                  <label className="label">{t('age')}</label>
                  {isEditing ? (
                    <input
                      type="number"
                      name="age"
                      value={profileData.age}
                      onChange={handleInputChange}
                      className="input"
                      min="1"
                      max="150"
                    />
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaCalendarAlt className="text-gray-400" />
                      <span>{profileData.age} years</span>
                    </div>
                  )}
                </div>

                <div className="form-group">
                  <label className="label">{t('gender')}</label>
                  {isEditing ? (
                    <select
                      name="gender"
                      value={profileData.gender}
                      onChange={handleInputChange}
                      className="input"
                    >
                      <option value="">Select Gender</option>
                      <option value="male">Male</option>
                      <option value="female">Female</option>
                      <option value="other">Other</option>
                    </select>
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaUser className="text-gray-400" />
                      <span className="capitalize">{profileData.gender}</span>
                    </div>
                  )}
                </div>

                <div className="form-group">
                  <label className="label">Blood Group</label>
                  {isEditing ? (
                    <select
                      name="blood_group"
                      value={profileData.blood_group}
                      onChange={handleInputChange}
                      className="input"
                    >
                      <option value="">Select Blood Group</option>
                      <option value="A+">A+</option>
                      <option value="A-">A-</option>
                      <option value="B+">B+</option>
                      <option value="B-">B-</option>
                      <option value="AB+">AB+</option>
                      <option value="AB-">AB-</option>
                      <option value="O+">O+</option>
                      <option value="O-">O-</option>
                    </select>
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaTint className="text-red-500" />
                      <span>{profileData.blood_group}</span>
                    </div>
                  )}
                </div>

                <div className="form-group">
                  <label className="label">Emergency Contact</label>
                  {isEditing ? (
                    <input
                      type="tel"
                      name="emergency_contact"
                      value={profileData.emergency_contact}
                      onChange={handleInputChange}
                      className="input"
                    />
                  ) : (
                    <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg">
                      <FaPhone className="text-gray-400" />
                      <span>{profileData.emergency_contact}</span>
                    </div>
                  )}
                </div>
              </div>

              <div className="form-group">
                <label className="label">{t('address')}</label>
                {isEditing ? (
                  <textarea
                    name="address"
                    value={profileData.address}
                    onChange={handleInputChange}
                    className="input resize-none"
                    rows={3}
                  />
                ) : (
                  <div className="flex items-start gap-2 p-3 bg-gray-50 rounded-lg">
                    <FaMapMarkerAlt className="text-gray-400 mt-1" />
                    <span>{profileData.address}</span>
                  </div>
                )}
              </div>

              <div className="form-group">
                <label className="label">Allergies</label>
                {isEditing ? (
                  <textarea
                    name="allergies"
                    value={profileData.allergies}
                    onChange={handleInputChange}
                    className="input resize-none"
                    rows={2}
                    placeholder="List any known allergies..."
                  />
                ) : (
                  <div className="flex items-start gap-2 p-3 bg-gray-50 rounded-lg">
                    <FaAllergies className="text-orange-500 mt-1" />
                    <span>{profileData.allergies || 'No known allergies'}</span>
                  </div>
                )}
              </div>

              <div className="form-group">
                <label className="label">Medical History</label>
                {isEditing ? (
                  <textarea
                    name="medical_history"
                    value={profileData.medical_history}
                    onChange={handleInputChange}
                    className="input resize-none"
                    rows={3}
                    placeholder="Brief medical history..."
                  />
                ) : (
                  <div className="flex items-start gap-2 p-3 bg-gray-50 rounded-lg">
                    <FaHeart className="text-red-500 mt-1" />
                    <span>{profileData.medical_history || 'No medical history recorded'}</span>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Prescriptions Tab */}
          {activeTab === 'prescriptions' && (
            <div className="space-y-6">
              {prescriptions.length > 0 ? (
                prescriptions.map((prescription) => (
                  <div key={prescription.id} className="border rounded-lg p-6">
                    <div className="flex items-start justify-between mb-4">
                      <div>
                        <h4 className="font-semibold text-lg text-gray-900">
                          {prescription.diagnosis}
                        </h4>
                        <p className="text-gray-600">
                          {prescription.doctor_name} - {prescription.doctor_specialty}
                        </p>
                        <p className="text-sm text-gray-500">
                          {formatDate(prescription.date)}
                        </p>
                      </div>
                      <div className="flex gap-2">
                        <button className="btn btn-sm btn-outline flex items-center gap-2">
                          <FaEye />
                          View
                        </button>
                        <button className="btn btn-sm btn-primary flex items-center gap-2">
                          <FaDownload />
                          Download
                        </button>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <h5 className="font-medium text-gray-900 mb-3">Medicines</h5>
                        <div className="space-y-2">
                          {prescription.medicines.map((medicine, index) => (
                            <div key={index} className="p-3 bg-gray-50 rounded-lg">
                              <div className="font-medium text-gray-900">{medicine.name}</div>
                              <div className="text-sm text-gray-600">{medicine.dosage}</div>
                              <div className="text-sm text-gray-500">Duration: {medicine.duration}</div>
                            </div>
                          ))}
                        </div>
                      </div>

                      <div>
                        <h5 className="font-medium text-gray-900 mb-3">Instructions</h5>
                        <div className="p-3 bg-blue-50 rounded-lg">
                          <p className="text-blue-800">{prescription.instructions}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-12">
                  <FaPrescription className="mx-auto text-6xl text-gray-300 mb-4" />
                  <h3 className="text-xl font-medium text-gray-900 mb-2">No prescriptions found</h3>
                  <p className="text-gray-600">Your prescription history will appear here</p>
                </div>
              )}
            </div>
          )}

          {/* Medical History Tab */}
          {activeTab === 'history' && (
            <div className="space-y-4">
              {medicalHistory.length > 0 ? (
                medicalHistory.map((record) => (
                  <div key={record.id} className="flex items-center justify-between p-4 border rounded-lg">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center">
                        <FaFileAlt className="text-blue-600" />
                      </div>
                      <div>
                        <div className="font-medium text-gray-900">{record.description}</div>
                        <div className="text-sm text-gray-600">{record.doctor}</div>
                        <div className="text-sm text-gray-500">{formatDate(record.date)}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="px-3 py-1 bg-blue-100 text-blue-800 text-sm rounded-full">
                        {record.type}
                      </span>
                      <span className="px-3 py-1 bg-green-100 text-green-800 text-sm rounded-full">
                        {record.status}
                      </span>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center py-12">
                  <FaHistory className="mx-auto text-6xl text-gray-300 mb-4" />
                  <h3 className="text-xl font-medium text-gray-900 mb-2">No medical history found</h3>
                  <p className="text-gray-600">Your medical history will appear here</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Profile;
